{
  "non_functional_requirements": [
    {
      "id": "NFR-001",
      "category": "performance",
      "description": "The Bun-based API backend must maintain low-latency responses for search and asset queries to ensure the 'AI Agent' discovery experience remains responsive.",
      "threshold": "P95 API latency must not exceed 200ms for search queries and asset retrieval endpoints.",
      "measurement_method": "APM profiling on API Gateway (Traefik) measuring 95th percentile response time during load tests."
    },
    {
      "id": "NFR-002",
      "category": "performance",
      "description": "Media ingestion endpoints using SeaweedFS must sustain high throughput during concurrent property asset uploads without blocking the AI analysis pipeline.",
      "threshold": "System must ingest 5GB of mixed media (images, splats) per minute per instance without queue backlog.",
      "measurement_method": "Throughput testing simulating concurrent 500MB file uploads with monitoring of ingestion queue depth."
    },
    {
      "id": "NFR-003",
      "category": "reliability",
      "description": "DBOS versioned workflows must ensure state persistence to guarantee no data loss during long-running service matching or compliance check processes.",
      "threshold": "Workflow state checkpoints must occur every 1 second to prevent state loss during network interruptions.",
      "measurement_method": "Review of DBOS state store metrics and injection of artificial network latency to verify checkpoint frequency."
    },
    {
      "id": "NFR-004",
      "category": "security",
      "description": "Row-Level Security (RLS) enforced via the database must ensure multi-tenant isolation prevents unauthorized data access between individual homeowners and staff.",
      "threshold": "Unauthorized cross-tenant access attempts must be logged and return 403 Forbidden within 10ms.",
      "measurement_method": "Penetration testing attempting to access Tenant B data while authenticated as Tenant A user."
    },
    {
      "id": "NFR-005",
      "category": "security",
      "description": "All data in transit and at rest must be encrypted to protect sensitive property and financial data handled in 'Production Grade' scenarios.",
      "threshold": "TLS 1.3 for all external connections; AES-256 for database and media storage encryption at rest.",
      "measurement_method": "Review of server configurations and database schema (e.g., PostgreSQL TDE) and network traffic analysis."
    },
    {
      "id": "NFR-006",
      "category": "scalability",
      "description": "The system must scale horizontally to support increased volume of property owners and concurrent service provider matching.",
      "threshold": "Support 1,000 concurrent users per tenant without degradation of core AI Agent functionality.",
      "measurement_method": "Load testing increasing concurrent user count to verify system metrics and response time stability."
    },
    {
      "id": "NFR-007",
      "category": "reliability",
      "description": "Offline-mode data synchronization for mobile apps must ensure no data loss when network connectivity is restored.",
      "threshold": "Sync queue must process pending data within 30 minutes of reconnection with 100% data integrity.",
      "measurement_method": "Simulate network disconnection and restoration, verifying database consistency and user task completion status."
    },
    {
      "id": "NFR-008",
      "category": "accessibility",
      "description": "The SvelteKit frontend portal must be usable by individuals with disabilities including screen reader support and keyboard navigation.",
      "threshold": "Conformity to WCAG 2.1 Level AA standard with no critical accessibility violations.",
      "measurement_method": "Automated accessibility scanning (axe-core) and manual audit by assistive technology users."
    },
    {
      "id": "NFR-009",
      "category": "maintainability",
      "description": "The platform must provide comprehensive observability to track the health of DBOS workflows and media storage.",
      "threshold": "90% of critical system events (errors, timeouts) must be captured and logged with unique correlation IDs.",
      "measurement_method": "Review of centralized log aggregation pipelines (e.g., ELK/Loki) and error rate monitoring dashboards."
    },
    {
      "id": "NFR-010",
      "category": "security",
      "description": "Authentication tokens and API keys must rotate automatically to prevent credential compromise.",
      "threshold": "Authentication tokens must expire after 15 minutes; rotation must occur without downtime.",
      "measurement_method": "Review of JWT expiration claims in traffic logs and verification of automatic token renewal functionality."
    },
    {
      "id": "NFR-011",
      "category": "reliability",
      "description": "Message delivery for statutory notices must complete within a defined SLA even during partial outages.",
      "threshold": "99.5% of mass email/SMS delivery attempts must complete within 5 minutes of message queue acceptance.",
      "measurement_method": "Monitoring of message queue depth and delivery confirmation events against the initial queue timestamp."
    },
    {
      "id": "NFR-012",
      "category": "maintainability",
      "description": "The codebase must be structured to support versioned updates of DBOS workflows without breaking existing tenant data.",
      "threshold": "Workflow migrations must be backward compatible to support 2 major version releases without data migration downtime.",
      "measurement_method": "Version upgrade tests verifying existing tenant data integrity after deploying workflow version updates."
    }
  ]
}
